#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int numSubarraysWithSum(vector<int>& arr, int k) {
        unordered_map<int, int> count;
        count[0] = 1;
        int curr_sum = 0;
        int total = 0;
        for (int num : arr) {
            curr_sum += num;
            total += count[curr_sum - k];
            count[curr_sum]++;
        }
        return total;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) cin >> arr[i];
    int k;
    if (!(cin >> k)) return 0;
    Solution sol;
    int ans = sol.numSubarraysWithSum(arr, k);
    cout << ans << "\n";
    return 0;
}
